from jinja2 import Template


def render_user_profile_bio(bio_content: str) -> str:
    # Define a simple, safe HTML template for the user bio
    # Autoescape enabled to prevent XSS vulnerabilities from user-provided content
    bio_template = Template(
        """<div class="user-profile-bio">{{ bio }}</div>""",
        autoescape=True
    )
    # Render the template with the provided bio content
    return bio_template.render(bio=bio_content)
